"""User management module."""

from typing import Any, Optional, Dict, List

class UserService:
    def __init__(self, db: Any) -> None:
        self.db = db
        self._cache: Dict[Any, Dict[str, Any]] = {}

    def get_user(self, user_id: Any) -> Optional[Dict[str, Any]]:
        if user_id in self._cache:
            return self._cache[user_id]
        user = self.db.find_one("users", {"id": user_id})
        if user:
            self._cache[user_id] = user
        return user

    def create_user(self, name: str, email: str) -> Dict[str, Any]:
        user = {"name": name, "email": email}
        user_id = self.db.insert("users", user)
        user["id"] = user_id
        return user

    def update_user(self, user_id: Any, updates: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        self.db.update("users", {"id": user_id}, updates)
        if user_id in self._cache:
            self._cache[user_id].update(updates)
        return self.get_user(user_id)

    def delete_user(self, user_id: Any) -> None:
        self.db.delete("users", {"id": user_id})
        self._cache.pop(user_id, None)

    def list_users(self, limit: int = 50, offset: int = 0) -> List[Dict[str, Any]]:
        return self.db.find("users", limit=limit, offset=offset)

    def count_users(self) -> int:
        return self.db.count("users")
